int dp[N][2], a[N], pre[N][2];
void solve(int CASE)
{
	int n; cin >> n;
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n)dp[i][0] = -INF, dp[i][1] = INF;

	// 0：i 加入递增序列，递减序列的最大末尾值
	// 1：i 加入递减序列，递增序列的最小末尾值
	dp[1][0] = INF, dp[1][1] = -INF;
	fa(i, 2, n) {
		if (a[i] > a[i - 1]) {
			// 递增序列末尾第二个：a[i - 1]，递增序列末尾第一个：a[i]
			dp[i][0] = dp[i - 1][0]; 
			pre[i][0] = 0;
			if (a[i] > dp[i - 1][1]) { 
				if (dp[i][0] < a[i - 1]) {
					// 递减序列末尾：a[i - 1]，递增序列末尾：a[i]
					dp[i][0] = a[i - 1];
					pre[i][0] = 1;
				}
			}

			if (a[i] < dp[i - 1][0]) {
				// 递增序列末尾：a[i - 1]，递减序列末尾：a[i]
				dp[i][1] = a[i - 1];
				pre[i][1] = 0;
			}
		}
		else if (a[i] < a[i - 1]) {
			// 递减序列末尾第二个：a[i - 1]，递减序列末尾第一个：a[i]
			dp[i][1] = dp[i - 1][1];
			pre[i][1] = 1;
			if (a[i] < dp[i - 1][0]) {
				if (dp[i][1] > a[i - 1]) {
					// 递增序列末尾：a[i - 1]，递减序列末尾：a[i]
					dp[i][1] = a[i - 1];
					pre[i][1] = 0;
				}
			}

			if (a[i] > dp[i - 1][1]) {
				// 递减序列末尾：a[i - 1]，递增序列末尾：a[i]
				dp[i][0] = a[i - 1]; 
				pre[i][0] = 1;
			}
		}
		else {
			if (a[i] > dp[i - 1][1]) {
				// 递减序列末尾：a[i - 1]，递增序列末尾：a[i]
				dp[i][0] = a[i - 1];
				pre[i][0] = 1;
			}

			if (a[i] < dp[i - 1][0]) {
				// 递增序列末尾：a[i - 1]，递减序列末尾：a[i]
				dp[i][1] = a[i - 1];
				pre[i][1] = 0;
			}
		}
	}

	if (dp[n][0] == -INF and dp[n][1] == INF)cout << "NO" << endl;
	else {
		cout << "YES" << endl;

		int now = 0;
		var ans = vector<int>(n + 1);
		if (dp[n][0] != -INF)now = 0;
		else now = 1;

		fb(i, n, 1) {
			ans[i] = now;
			now = pre[i][now];
		}

		fa(i, 1, n)cout << ans[i] << " \n"[i == n];
	}
	return;
}
